## Summary: Form Component Patterns in Raycast Clone

### 1. **Component Export Structure** (`index.ts`)
```typescript
export { Form } from './form';
export { FormCheckbox } from './form_checkbox';
export { FormDatePicker } from './form_date_picker';
export { FormDropdown } from './form_dropdown';
export type { FormDropdownOption } from './form_dropdown';
export { FormPasswordField } from './form_password_field';
export { FormTextArea } from './form_text_area';
export { FormTextField } from './form_text_field';
```

**Key Pattern**: Only components and their exported types are re-exported. FormField is NOT exported (internal wrapper).

---

### 2. **Form Container Component** (`form.tsx`)
```typescript
interface FormProps {
  children: ReactNode;
  onSubmit?: () => void;
}

export function Form({ children, onSubmit }: FormProps) {
  function handleSubmit(e: FormEvent) {
    e.preventDefault();
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Enter' && e.metaKey && onSubmit) {
      e.preventDefault();
      onSubmit();
    }
  }

  return (
    <form
      className="form"
      onSubmit={handleSubmit}
      onKeyDown={handleKeyDown}
      noValidate
    >
      <div className="form__fields">{children}</div>
    </form>
  );
}
```

**Key Patterns**:
- Prevents default form submission
- Triggers onSubmit via Cmd+Enter (metaKey), not Enter alone
- Uses `noValidate` to handle validation with custom logic
- Wraps children in `form__fields` container

---

### 3. **FormField Wrapper** (`form_field.tsx`) - Internal Pattern
```typescript
interface FormFieldProps {
  label: string;
  description?: string;
  error?: string;
  children: ReactNode;
  htmlFor?: string;
}

export function FormField({
  label,
  description,
  error,
  children,
  htmlFor,
}: FormFieldProps) {
  return (
    <div className={`form-field${error ? ' form-field--error' : ''}`}>
      <div className="form-field__header">
        <label className="form-field__label" htmlFor={htmlFor}>
          {label}
        </label>
        {error && (
          <span
            className="form-field__error"
            id={htmlFor ? `${htmlFor}-error` : undefined}
          >
            {error}
          </span>
        )}
        {!error && description && (
          <span className="form-field__description">{description}</span>
        )}
      </div>
      <div className="form-field__control">{children}</div>
    </div>
  );
}
```

**Key Patterns**:
- All form fields wrap their input with FormField
- Supports optional label, description, and error
- Error ID follows pattern: `${htmlFor}-error` (used for `aria-describedby`)
- Conditionally shows error or description (not both)
- Error state adds `form-field--error` modifier class
- Label connects to input via `htmlFor` attribute

---

### 4. **FormTextField Pattern** (`form_text_field.tsx`)
```typescript
interface FormTextFieldProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  description?: string;
  error?: string;
  autoFocus?: boolean;
}

export function FormTextField({
  label,
  value,
  onChange,
  placeholder,
  description,
  error,
  autoFocus,
}: FormTextFieldProps) {
  const id = useId();

  return (
    <FormField
      label={label}
      description={description}
      error={error}
      htmlFor={id}
    >
      <input
        id={id}
        className="form-input"
        type="text"
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        autoFocus={autoFocus}
        spellCheck={false}
        autoComplete="off"
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? `${id}-error` : undefined}
      />
    </FormField>
  );
}
```

**Key Patterns**:
- Uses `useId()` for unique ID generation (matches the id from FormField's `htmlFor`)
- ARIA attributes: `aria-invalid` and `aria-describedby` only when error exists
- Disables spellcheck and autocomplete by default
- Passes all label/description/error logic to FormField wrapper
- onChange callback receives string value directly

---

### 5. **FormPasswordField Pattern** (`form_password_field.tsx`) - Extended Pattern
```typescript
interface FormPasswordFieldProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  description?: string;
  error?: string;
  autoFocus?: boolean;
}

export function FormPasswordField({
  label,
  value,
  onChange,
  placeholder,
  description,
  error,
  autoFocus,
}: FormPasswordFieldProps) {
  const id = useId();
  const [revealed, setRevealed] = useState(false);

  return (
    <FormField
      label={label}
      description={description}
      error={error}
      htmlFor={id}
    >
      <div className="form-password-wrapper">
        <input
          id={id}
          className="form-input form-input--password"
          type={revealed ? 'text' : 'password'}
          value={value}
          onChange={e => onChange(e.target.value)}
          placeholder={placeholder}
          autoFocus={autoFocus}
          spellCheck={false}
          autoComplete="current-password"
          aria-invalid={error ? true : undefined}
          aria-describedby={error ? `${id}-error` : undefined}
        />
        <button
          type="button"
          className="form-password-toggle"
          onClick={() => setRevealed(prev => !prev)}
          aria-label={revealed ? 'Hide password' : 'Show password'}
        >
          {revealed ? <EyeOffIcon /> : <EyeIcon />}
        </button>
      </div>
    </FormField>
  );
}
```

**Key Patterns**:
- Extends FormTextField with password reveal/hide toggle
- Uses `useState` for revealed state
- Icon components are internal helper functions (EyeIcon, EyeOffIcon)
- Wrapper div (form-password-wrapper) creates relative positioning context for toggle button
- Toggle button has `aria-label` that updates based on state
- Uses `autoComplete="current-password"` for password managers
- When type switches, input type changes: `type={revealed ? 'text' : 'password'}`

---

### 6. **FormCheckbox Pattern** (`form_checkbox.tsx`) - Non-FormField Variation
```typescript
interface FormCheckboxProps {
  label: string;
  checked: boolean;
  onChange: (checked: boolean) => void;
  description?: string;
  error?: string;
}

export function FormCheckbox({
  label,
  checked,
  onChange,
  description,
  error,
}: FormCheckboxProps) {
  const id = useId();

  return (
    <div className={`form-checkbox${error ? ' form-checkbox--error' : ''}`}>
      <div className="form-checkbox__row">
        <input
          id={id}
          type="checkbox"
          className="form-checkbox__input"
          checked={checked}
          onChange={e => onChange(e.target.checked)}
          aria-invalid={error ? true : undefined}
          aria-describedby={error ? `${id}-error` : undefined}
        />
        <div
          className={`form-checkbox__box${checked ? ' form-checkbox__box--checked' : ''}`}
          aria-hidden="true"
        >
          {checked && (
            <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
              <path
                d="M2 5L4.5 7.5L8 2.5"
                stroke="currentColor"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          )}
        </div>
        <label className="form-checkbox__label" htmlFor={id}>
          {label}
        </label>
      </div>
      {error && (
        <span className="form-checkbox__error" id={`${id}-error`}>
          {error}
        </span>
      )}
      {!error && description && (
        <span className="form-checkbox__description">{description}</span>
      )}
    </div>
  );
}
```

**Key Patterns**:
- Does NOT use FormField wrapper (custom layout with checkbox visual)
- Creates own error state class: `form-checkbox--error`
- Custom visual checkbox: hidden native input + styled div with SVG checkmark
- Uses `aria-hidden="true"` on custom checkbox visual
- onChange callback receives boolean directly
- Same error/description logic as FormField

---

### 7. **FormDropdown Pattern** (`form_dropdown.tsx`)
```typescript
export interface FormDropdownOption {
  label: string;
  value: string;
}

interface FormDropdownProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  options: FormDropdownOption[];
  placeholder?: string;
  description?: string;
  error?: string;
}

export function FormDropdown({
  label,
  value,
  onChange,
  options,
  placeholder,
  description,
  error,
}: FormDropdownProps) {
  const id = useId();

  return (
    <FormField
      label={label}
      description={description}
      error={error}
      htmlFor={id}
    >
      <select
        id={id}
        className="form-input form-input--select"
        value={value}
        onChange={e => onChange(e.target.value)}
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? `${id}-error` : undefined}
      >
        {placeholder && !value && (
          <option value="" disabled hidden>
            {placeholder}
          </option>
        )}
        {options.map(option => (
          <option key={option.value} value={option.value}>
            {option.label}
          </option>
        ))}
      </select>
    </FormField>
  );
}
```

**Key Patterns**:
- Exports FormDropdownOption type separately
- Uses native `<select>` element with form-input styling
- Placeholder option is disabled and hidden (good UX pattern)
- Maps options array using value as key
- Same FormField wrapper pattern as text field

---

### 8. **SCSS Patterns** (`form.scss`)

**Container & Layout:**
```scss
.form {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow-y: auto;
  padding: $space-3;
}

.form__fields {
  display: flex;
  flex-direction: column;
  gap: $space-4;
}
```

**FormField Wrapper:**
```scss
.form-field {
  display: flex;
  flex-direction: column;
  gap: $space-1;
}

.form-field__header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: $space-2;
}

.form-field__label {
  font-size: $font-sm;
  color: $text-600;
  font-weight: $font-weight-semibold;
}

.form-field__description {
  font-size: $font-xs;
  color: $text-400;
}

.form-field__error {
  font-size: $font-xs;
  color: $color-destructive;
}
```

**Input Base Styles:**
```scss
.form-input {
  width: 100%;
  padding: $space-2 $space-3;
  background: $color-background;
  border: 1px solid $border-100;
  border-radius: $radius-md;
  color: $color-text-primary;
  font-family: $font-family;
  font-size: $font-md;
  outline: none;
  transition: border-color $transition-fast ease;

  &::placeholder {
    color: $text-400;
  }

  &:focus {
    border-color: $color-accent;
  }

  .form-field--error & {
    border-color: $color-destructive;
  }
}
```

**Password Field Specific:**
```scss
.form-password-wrapper {
  position: relative;
  display: flex;
  align-items: center;
}

.form-input--password {
  padding-right: $space-8;
}

.form-password-toggle {
  position: absolute;
  right: $space-2;
  display: flex;
  align-items: center;
  justify-content: center;
  width: $space-6;
  height: $space-6;
  padding: 0;
  border: none;
  border-radius: $radius-sm;
  background: transparent;
  color: $text-400;
  cursor: pointer;
  transition: color $transition-fast ease;

  &:hover {
    color: $color-text-primary;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: 2px;
  }
}
```

**Checkbox Specific:**
```scss
.form-checkbox {
  display: flex;
  flex-direction: column;
  gap: $space-1;
}

.form-checkbox__row {
  display: flex;
  align-items: center;
  gap: $space-2;
}

$checkbox-size: 16px;

.form-checkbox__input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
  pointer-events: none;

  &:focus-visible + .form-checkbox__box {
    outline: 2px solid $color-accent;
    outline-offset: 2px;
  }
}

.form-checkbox__box {
  display: flex;
  align-items: center;
  justify-content: center;
  width: $checkbox-size;
  height: $checkbox-size;
  border: 1px solid $border-100;
  border-radius: $radius-sm;
  background: $color-background;
  color: $color-text-on-accent;
  pointer-events: none;
  flex-shrink: 0;
  transition: background-color $transition-fast ease, border-color $transition-fast ease;

  .form-checkbox--error & {
    border-color: $color-destructive;
  }

  &--checked {
    background: $color-accent;
    border-color: $color-accent;
  }
}
```

**Select Dropdown:**
```scss
.form-input--select {
  appearance: none;
  cursor: pointer;
  background-image: url("data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1L5 5L9 1' stroke='%2398989d' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E");
  background-repeat: no-repeat;
  background-position: right $space-3 center;
  padding-right: $space-7;

  option {
    background: $color-surface;
    color: $color-text-primary;
  }
}
```

**Key SCSS Patterns**:
- Uses parent selector with nested inputs: `.form-field--error & { ... }`
- Uses local SCSS variable for checkbox size: `$checkbox-size: 16px`
- Transitions on color/border-color (80ms via $transition-fast)
- Uses focus-visible for keyboard navigation highlight
- Hides native checkbox with absolute positioning + opacity 0
- Custom dropdown arrow via background-image (inline SVG)
- Consistent spacing using $space-* tokens
- All colors from $tokens.scss

---

