file.content:
@use '../../styles/tokens' as *;

$tag-picker-tag-height: 22px;
$tag-picker-menu-max-height: 180px;

.form-tag-picker {
  position: relative;
}

.form-tag-picker__input-area {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: $space-1;
  min-height: 34px;
  padding: $space-1 $space-2;
  background: $color-background;
  border: 1px solid $border-100;
  border-radius: $radius-md;
  cursor: text;
  transition: border-color $transition-fast ease;

  &:focus-within {
    border-color: $color-accent;
  }

  .form-field--error & {
    border-color: $color-destructive;
  }
}

.form-tag-picker__tag {
  display: inline-flex;
  align-items: center;
  gap: $space-half;
  height: $tag-picker-tag-height;
  padding: 0 $space-1 0 $space-2;
  background: rgba($color-accent, 0.15);
  color: $color-accent;
  border-radius: $radius-kbd;
  font-size: $font-xs;
  font-weight: $font-weight-medium;
  line-height: 1;
  flex-shrink: 0;
}

.form-tag-picker__tag-label {
  white-space: nowrap;
  max-width: 120px;
  overflow: hidden;
  text-overflow: ellipsis;
}

.form-tag-picker__tag-remove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 14px;
  height: 14px;
  padding: 0;
  border: none;
  border-radius: $radius-sm;
  background: transparent;
  color: $color-accent;
  cursor: pointer;
  opacity: 0.6;
  transition: opacity $transition-fast ease;

  &:hover {
    opacity: 1;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: 1px;
  }
}

.form-tag-picker__input {
  flex: 1;
  min-width: 60px;
  height: 24px;
  padding: 0;
  border: none;
  background: transparent;
  color: $color-text-primary;
  font-family: $font-family;
  font-size: $font-md;
  outline: none;

  &::placeholder {
    color: $text-400;
  }
}

.form-tag-picker__menu {
  position: absolute;
  top: calc(100% + $space-1);
  left: 0;
  right: 0;
  max-height: $tag-picker-menu-max-height;
  overflow-y: auto;
  margin: 0;
  padding: $space-1;
  list-style: none;
  background: $color-surface;
  border: 1px solid $border-100;
  border-radius: $radius-md;
  box-shadow: $shadow-popover;
  z-index: $z-dropdown;
}

.form-tag-picker__option {
  display: flex;
  align-items: center;
  height: 32px;
  padding: 0 $space-2;
  border-radius: $radius-kbd;
  font-size: $font-md;
  color: $color-text-primary;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &--active {
    background: $color-selection-background;
  }
}

